function solve(nums, k) {
    if (nums.length === 1) {
        return 0;
    }

    // Sort the array to easily find min and max
    nums.sort((a, b) => a - b);

    // We need to find the smallest number of elements to remove
    // such that the max is at most k times the min in the remaining array
    let minRemovals = nums.length - 1; // Worst case: remove all but one

    // Try all possible subarrays (after sorting)
    for (let i = 0; i < nums.length; i++) {
        // Start with the current element as the min
        let min = nums[i];
        let max = 0;
        let count = 0;

        // Check all elements from i to the end
        for (let j = i; j < nums.length; j++) {
            max = Math.max(max, nums[j]);
            if (max > min * k) {
                // If current max is too big, we need to remove this element
                count++;
            }
        }

        // The number of elements we can keep is (nums.length - count)
        // So the number of elements to remove is count
        minRemovals = Math.min(minRemovals, count);
    }

    return minRemovals;
}

